import{_ as t,c as a,o as r,ag as o}from"./chunks/framework.B-QRwBGS.js";const p=JSON.parse('{"title":"Frequently Asked Questions","description":"","frontmatter":{},"headers":[],"relativePath":"home/faq.md","filePath":"home/faq.md","lastUpdated":1782748376000}'),s={name:"home/faq.md"};function i(n,e,d,c,l,u){return r(),a("div",null,e[0]||(e[0]=[o('<h1 id="frequently-asked-questions" tabindex="-1">Frequently Asked Questions <a class="header-anchor" href="#frequently-asked-questions" aria-label="Permalink to &quot;Frequently Asked Questions&quot;">​</a></h1><p>This page contains answers to frequently asked questions about Fracture.</p><h2 id="what-platforms-does-fracture-support" tabindex="-1">What platforms does Fracture support? <a class="header-anchor" href="#what-platforms-does-fracture-support" aria-label="Permalink to &quot;What platforms does Fracture support?&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Platform</th><th>Status</th></tr></thead><tbody><tr><td>Windows</td><td>✅ Fully supported</td></tr><tr><td>macOS</td><td>✅ Fully supported</td></tr><tr><td>Linux</td><td>✅ Fully supported</td></tr><tr><td>GX.games</td><td>✅ Fully supported</td></tr><tr><td>Android</td><td>🚧 Untested</td></tr><tr><td>iOS</td><td>🚧 Untested</td></tr><tr><td>PS5</td><td>🚧 Untested</td></tr><tr><td>Xbox</td><td>🚧 Untested</td></tr><tr><td>Nintendo Switch</td><td>🚧 Untested</td></tr><tr><td>HTML5</td><td>❌ Not planned</td></tr></tbody></table><h2 id="what-versions-of-gamemaker-does-fracture-support" tabindex="-1">What versions of GameMaker does Fracture support? <a class="header-anchor" href="#what-versions-of-gamemaker-does-fracture-support" aria-label="Permalink to &quot;What versions of GameMaker does Fracture support?&quot;">​</a></h2><p>Fracture supports GameMaker version <a href="https://releases.gamemaker.io/release-notes/2026/0" target="_blank" rel="noreferrer">LTS 2026.0</a> and above.</p><h2 id="how-is-fracture-licensed-can-i-use-it-in-commercial-projects" tabindex="-1">How is Fracture licensed? Can I use it in commercial projects? <a class="header-anchor" href="#how-is-fracture-licensed-can-i-use-it-in-commercial-projects" aria-label="Permalink to &quot;How is Fracture licensed? Can I use it in commercial projects?&quot;">​</a></h2><p>Fracture is licensed under the <a href="https://github.com/glebtsereteli/Fracture/blob/main/LICENSE" target="_blank" rel="noreferrer">MIT license</a>, granting you full freedom to use it for any purpose, including commercial projects. The only requirement is to include the <code>Fracture License.txt</code> file that comes with the library package.</p><p>Mentioning my name (Gleb Tsereteli) in your game&#39;s credits would be greatly appreciated and would totally make my day, but it&#39;s entirely optional 🙂</p><h2 id="how-is-fracture-versioned" tabindex="-1">How is Fracture versioned? <a class="header-anchor" href="#how-is-fracture-versioned" aria-label="Permalink to &quot;How is Fracture versioned?&quot;">​</a></h2><p>Fracture follows Semantic Versioning using the <code>vMAJOR.MINOR.PATCH</code> format, where:</p><ul><li><strong>MAJOR</strong> increases when incompatible API changes are introduced. Updating to a new major version may require you to update your code.</li><li><strong>MINOR</strong> increases when new features are added in a backward-compatible way, so it&#39;s always safe to update.</li><li><strong>PATCH</strong> increases when backward-compatible bug fixes are made. These are also always safe to update to.</li></ul><h2 id="how-do-i-update-to-the-latest-version-of-fracture" tabindex="-1">How do I update to the latest version of Fracture? <a class="header-anchor" href="#how-do-i-update-to-the-latest-version-of-fracture" aria-label="Permalink to &quot;How do I update to the latest version of Fracture?&quot;">​</a></h2><ol><li>Back up your settings from the <code>FractureConfig</code> script.</li><li>Delete the <code>Fracture</code> folder from your project.</li><li>Repeat the <a href="/Fracture/pages/home/gettingStarted/gettingStarted#installation">Installation</a> process.</li><li>Reapply your config changes in the <code>FractureConfig</code> script.</li></ol><h2 id="do-my-objects-need-to-be-physics-enabled-to-fracture-them" tabindex="-1">Do my objects need to be physics-enabled to fracture them? <a class="header-anchor" href="#do-my-objects-need-to-be-physics-enabled-to-fracture-them" aria-label="Permalink to &quot;Do my objects need to be physics-enabled to fracture them?&quot;">​</a></h2><p>No. Fracture works on any instance regardless of its physics state, scale, or rotation, and creates the physics bodies for you. If the source instance is itself physics-enabled, its linear and angular velocity carry over to the resulting <a href="/Fracture/topics/pieces">Pieces</a>.</p><p>This means Fracture integrates cleanly even into games that don&#39;t otherwise use <a href="https://manual.gamemaker.io/lts/en/GameMaker_Language/GML_Reference/Physics/Physics.htm" target="_blank" rel="noreferrer">Physics</a>.</p><h2 id="what-happens-to-the-original-instance-when-i-fracture-it" tabindex="-1">What happens to the original instance when I fracture it? <a class="header-anchor" href="#what-happens-to-the-original-instance-when-i-fracture-it" aria-label="Permalink to &quot;What happens to the original instance when I fracture it?&quot;">​</a></h2><p>It&#39;s destroyed automatically. Every fracture call returns an <a href="https://manual.gamemaker.io/lts/en/GameMaker_Language/GML_Overview/Arrays.htm" target="_blank" rel="noreferrer">Array</a> of the created <a href="/Fracture/topics/pieces">Piece</a> instances, so you can keep working with them afterwards if needed.</p>',19)]))}const f=t(s,[["render",i]]);export{p as __pageData,f as default};
